#include <stdio.h>

int main() {
    int n, k;
    scanf("%d %d", &n, &k);

    if (n / 2 < k) {
        printf("0 0 %d", n);
    } else {
        int a = n / 2 / (k + 1);
        int b = n / 2 / (k + 1) * k;
        printf("%d %d %d", a, b, n - a - b);
    }

    return 0;
}
